// Returns a stream that yields responses from the server.
func (c *ReaderServiceNatsClient) StreamAsset(ctx context.Context, req *StreamAssetRequest) (*ReaderService_StreamAsset_ClientStream, error) {
	subject := c.subjectPrefix + ".stream_asset"

	var data []byte
	var err error
	if c.useJSON {
		data, err = protojson.Marshal(req)
	} else {
		data, err = proto.Marshal(req)
	}
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	// Create inbox for receiving streamed responses
	inbox := nats.NewInbox()
	receiver, err := newClientStreamReceiver(c.nc, inbox, false)
	if err != nil {
		return nil, fmt.Errorf("failed to setup stream: %w", err)
	}

	// Send request with our inbox as Reply-To header
	msg := &nats.Msg{
		Subject: subject,
		Data:    data,
		Header:  nats.Header{},
	}
	msg.Header.Set("Reply-To", inbox)

	// Add outgoing headers from context
	if headers := OutgoingHeaders(ctx); headers != nil {
		for k, v := range headers {
			for _, val := range v {
				msg.Header.Add(k, val)
			}
		}
	}

	if err := c.nc.PublishMsg(msg); err != nil {
		receiver.Close()
		return nil, fmt.Errorf("failed to send streaming request: %w", err)
	}

	return &ReaderService_StreamAsset_ClientStream{
		receiver: receiver,
		useJSON:  c.useJSON,
	}, nil
}

