// ReaderService_Upstream_ClientStream is the client-side sender stream for Upstream.
type ReaderService_Upstream_ClientStream struct {
	nc      *nats.Conn
	sendTo  string // Server's inbox
	replyTo string // Our inbox for final response
	useJSON bool
	seq     int
	mu      sync.Mutex
}

// Send sends a message to the server.
func (s *ReaderService_Upstream_ClientStream) Send(msg *UpstreamRequest) error {
	var data []byte
	var err error
	if s.useJSON {
		data, err = protojson.Marshal(msg)
	} else {
		data, err = proto.Marshal(msg)
	}
	if err != nil {
		return fmt.Errorf("failed to marshal stream message: %w", err)
	}
	s.mu.Lock()
	s.seq++
	seq := s.seq
	s.mu.Unlock()
	m := &nats.Msg{
		Subject: s.sendTo,
		Data:    data,
		Header:  nats.Header{},
	}
	m.Header.Set(natsStreamSeqHeader, strconv.Itoa(seq))
	return s.nc.PublishMsg(m)
}

// CloseAndRecv signals end of client messages and waits for the server's response.
func (s *ReaderService_Upstream_ClientStream) CloseAndRecv(ctx context.Context) (*UpstreamResponse, error) {
	// Send end-of-stream marker
	m := &nats.Msg{
		Subject: s.sendTo,
		Header:  nats.Header{},
	}
	m.Header.Set(natsStreamEndHeader, "true")
	if err := s.nc.PublishMsg(m); err != nil {
		return nil, fmt.Errorf("failed to close send: %w", err)
	}

	// Wait for final response on our reply inbox
	sub, err := s.nc.SubscribeSync(s.replyTo)
	if err != nil {
		return nil, fmt.Errorf("failed to subscribe for response: %w", err)
	}
	defer sub.Unsubscribe()

	natsMsg, err := sub.NextMsgWithContext(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to receive response: %w", err)
	}

	var resp UpstreamResponse
	if s.useJSON {
		if err := protojson.Unmarshal(natsMsg.Data, &resp); err != nil {
			return nil, fmt.Errorf("failed to decode response: %w", err)
		}
	} else {
		if err := proto.Unmarshal(natsMsg.Data, &resp); err != nil {
			return nil, fmt.Errorf("failed to decode response: %w", err)
		}
	}
	return &resp, nil
}

// Upstream initiates a client-streaming RPC call.
func (c *ReaderServiceNatsClient) Upstream(ctx context.Context) (*ReaderService_Upstream_ClientStream, error) {
	subject := c.subjectPrefix + ".upstream"

	// Create inbox for receiving the final response
	replyInbox := nats.NewInbox()

	// Send initial handshake to get server's inbox
	msg := &nats.Msg{
		Subject: subject,
		Header:  nats.Header{},
	}
	msg.Header.Set("Reply-To", replyInbox)

	ackMsg, err := c.nc.RequestMsgWithContext(ctx, msg)
	if err != nil {
		return nil, fmt.Errorf("failed to initiate client stream: %w", err)
	}

	serverInbox := ackMsg.Header.Get(natsStreamInboxHeader)
	if serverInbox == "" {
		return nil, fmt.Errorf("server did not provide stream inbox")
	}

	return &ReaderService_Upstream_ClientStream{
		nc:      c.nc,
		sendTo:  serverInbox,
		replyTo: replyInbox,
		useJSON: c.useJSON,
	}, nil
}

